## Shell command execution and output capture for the get tool.
##
## :Author: WaterRun
## :GitHub: https://github.com/Water-Run/get
## :Date: 2026-04-14
## :File: exec.nim
## :License: AGPL-3.0
##
## This module provides procedures to execute shell commands
## generated by the LLM, capture their combined stdout/stderr
## output, and enforce safety constraints including command-pattern
## regex validation and interactive manual-confirm gating.  Commands
## are run through the configured shell via startProcess with the
## bundled bin/ directory prepended to PATH so that shipped tools
## (rg, fd, sg, pmc, treepp/tree) are available to generated
## commands.
##
## The regex engine is the pure-Nim ``regex`` package, eliminating
## the runtime dependency on libpcre and enabling fully static
## binaries.
##
## The manual-confirm prompt reads from the controlling terminal
## directly (/dev/tty on Unix, CONIN$ on Windows) so that it works
## regardless of stdin redirection or async event-loop state.

{.experimental: "strictFuncs".}

import std/[envvars, os, osproc, strtabs, streams,
            strformat, strutils]

import regex

import utils

# ---------------------------------------------------------------------------
# Types
# ---------------------------------------------------------------------------

## Encapsulates the result of a shell command execution.
type
  ExecResult* = object
    output*: string   ## Combined stdout and stderr output.
    exitCode*: int    ## Process exit code (0 = success).

# ---------------------------------------------------------------------------
# Private helpers
# ---------------------------------------------------------------------------

## Builds the argument list for invoking a command through the given
## shell.  PowerShell/pwsh receives ``-NoProfile -NonInteractive
## -Command <cmd>``; cmd.exe receives ``/C <cmd>``; everything else
## (bash, zsh, sh, fish …) receives ``-c <cmd>``.
##
## :param shell: Shell executable name or path.
## :param command: The command string to execute.
## :returns: A seq of shell arguments.
func implBuildShellArgs(
  shell: string,
  command: string
): seq[string] =
  let lower = toLowerAscii(shell)
  if lower.contains("powershell") or
      lower.contains("pwsh"):
    result = @[
      "-NoProfile", "-NonInteractive",
      "-Command", command
    ]
  elif lower.contains("cmd"):
    result = @["/C", command]
  else:
    result = @["-c", command]

## Creates a StringTableRef containing the current environment with
## binDir prepended to PATH.  Returns nil when binDir is empty or
## does not exist, meaning the child process inherits the parent
## environment unchanged.
##
## :param binDir: Absolute path to the bundled bin directory.
## :returns: A modified environment table, or nil.
proc implBuildEnv(binDir: string): StringTableRef =
  if binDir.len == 0 or not dirExists(binDir):
    return nil
  when defined(windows):
    var env = newStringTable(modeCaseInsensitive)
  else:
    var env = newStringTable(modeCaseSensitive)
  for key, val in envPairs():
    env[key] = val
  var curPath = ""
  if env.hasKey("PATH"):
    curPath = env["PATH"]
  when defined(windows):
    env["PATH"] = binDir & ";" & curPath
  else:
    env["PATH"] = binDir & ":" & curPath
  result = env

# ---------------------------------------------------------------------------
# Public API
# ---------------------------------------------------------------------------

## Validates a command string against a regular-expression pattern.
## Returns true when the pattern is found anywhere in the command.
## The caller is expected to reject execution when this returns
## false.
##
## :param command: The command to validate.
## :param pattern: A regular-expression string.
## :returns: true if the pattern matches.
## :raises: GetError: If the pattern is not a valid regex.
##
## .. code-block:: nim
##   runnableExamples:
##     assert validateCommandPattern("ls -la", "^ls")
##     assert not validateCommandPattern("rm -rf /", "^ls")
proc validateCommandPattern*(
  command: string,
  pattern: string
): bool =
  try:
    result = command.contains(re2(pattern))
  except CatchableError:
    raise newException(GetError,
      fmt"invalid command-pattern regex: {pattern}")

## Displays the command on stderr and reads a single line from
## the controlling terminal.  Returns true only when the user
## types "y" (case-insensitive).  The terminal is opened directly
## via /dev/tty (Unix) or CONIN$ (Windows) so that the prompt
## works correctly regardless of stdin state.
##
## :param command: The command awaiting confirmation.
## :returns: true if the user confirms with "y".
##
## .. code-block:: nim
##   runnableExamples:
##     # Interactive — cannot be tested non-interactively.
##     discard
proc confirmExecution*(command: string): bool =
  stderr.write(
    fmt"execute: {command}" & "\nconfirm? (y/N): ")
  stderr.flushFile()
  try:
    when defined(windows):
      let tty = open("CONIN$", fmRead)
    else:
      let tty = open("/dev/tty", fmRead)
    try:
      let response = tty.readLine()
      result = toLowerAscii(response.strip()) == "y"
    finally:
      tty.close()
  except IOError, EOFError, OSError:
    result = false

## Executes a command string through the specified shell and returns
## the captured combined output together with the exit code.  When
## binDir is non-empty and exists, it is prepended to PATH so that
## bundled tools are available to the command.
##
## :param command: The command to execute.
## :param shell: Shell executable name or path.
## :param binDir: Optional bundled-binary directory to prepend to
##                PATH.
## :returns: An ExecResult with captured output and exit code.
## :raises: GetError: If the shell process cannot be started.
##
## .. code-block:: nim
##   runnableExamples:
##     # Platform-specific — illustrative only.
##     discard
proc executeCommand*(
  command: string,
  shell: string,
  binDir: string = ""
): ExecResult =
  let args = implBuildShellArgs(shell, command)
  let env = implBuildEnv(binDir)
  var p: Process
  try:
    p = startProcess(
      shell,
      args = args,
      env = env,
      options = {poStdErrToStdOut, poUsePath}
    )
  except OSError as e:
    raise newException(GetError,
      fmt"cannot start shell '{shell}': {e.msg}")
  let output = p.outputStream.readAll()
  let exitCode = p.waitForExit()
  p.close()
  result = ExecResult(
    output: output,
    exitCode: exitCode
  )